html[saved-theme="dark"] body .callout .callout-title {
  background: rgba(0, 0, 0, 0) none repeat scroll 0% 0% / auto padding-box border-box;
  background-color: rgba(0, 0, 0, 0);
  border-bottom-color: rgb(205, 214, 244);
  border-bottom-left-radius: 0px;
  border-bottom-right-radius: 0px;
  border-bottom-width: 0px;
  border-left-color: rgb(205, 214, 244);
  border-left-width: 0px;
  border-right-color: rgb(205, 214, 244);
  border-right-width: 0px;
  border-top-color: rgb(205, 214, 244);
  border-top-left-radius: 0px;
  border-top-right-radius: 0px;
  border-top-width: 0px;
  color: var(--callout-color);
  gap: 4px;
  padding-block-end: 0px;
  padding-block-start: 0px;
  padding-bottom: 0px;
  padding-inline-end: 0px;
  padding-inline-start: 0px;
  padding-left: 0px;
  padding-right: 0px;
  padding-top: 0px;
}

html[saved-theme="dark"] body .callout .callout-title > .callout-title-inner > p {
  --font-weight: var(--callout-title-weight);
  color: var(--callout-title-color);
  font-weight: var(--font-weight);
}

html[saved-theme="dark"] body .callout > .callout-content {
  background: rgba(0, 0, 0, 0) none repeat scroll 0% 0% / auto padding-box border-box;
  background-color: var(--callout-content-background);
  color: var(--text-normal);
  padding-block-end: 0px;
  padding-block-start: 0px;
  padding-bottom: 0px;
  padding-inline-end: 0px;
  padding-inline-start: 0px;
  padding-left: 0px;
  padding-right: 0px;
  padding-top: 0px;
}

html[saved-theme="dark"] body .callout[data-callout="abstract"] {
  --bases-embed-border-color: color-mix(in oklch, var(--callout-color) 25%, var(--background-primary) 50%);
  --bases-table-border-color: color-mix(in oklch, var(--callout-color) 25%, var(--background-primary) 50%);
  --bases-table-header-background-hover: color-mix(in oklch, var(--callout-color) 10%, transparent);
  --callout-color: var(--callout-summary);
  --table-border-color: color-mix(in oklch, var(--callout-color) 25%, var(--background-primary) 50%);
  background: rgba(116, 199, 236, 0.1) none repeat scroll 0% 0% / auto padding-box border-box;
  background-color: rgb(var(--callout-color), 10%);
  border-bottom-color: rgba(116, 199, 236, 0.6);
  border-bottom-left-radius: 4px;
